@push('scripts')
<script src="https://api.tomtom.com/maps-sdk-for-web/cdn/6.x/6.25.0/maps/maps-web.min.js"></script>
<script>
function tourView() {
    const stopBaseUrl = @js(url('/sck/routen/stopps'));
    const reorderUrl = @js(route('sck.routen.reorder', $tour));
    const tomTomKey = @js(config('services.tomtom.key'));
    const routePoints = @js($tour->routePoints());
    const startLocation = @js($tour->start_snapshot);
    const endLocation = @js($tour->end_snapshot);
    const newStopCustomers = @js($customers->map(fn ($customer) => ['id' => $customer->id, 'address' => $customer->full_address, 'phone' => $customer->phone, 'name' => $customer->name])->values());
    const editableStops = @js($tour->stops->map(fn ($stop) => ['id' => $stop->id, 'title' => $stop->title, 'address' => $stop->address_snapshot['formatted'] ?? '', 'customer_id' => $stop->customer_id, 'type' => $stop->type, 'service_minutes' => $stop->service_minutes, 'priority' => $stop->priority, 'window_start' => $stop->window_start ? substr((string) $stop->window_start, 0, 5) : '', 'window_end' => $stop->window_end ? substr((string) $stop->window_end, 0, 5) : '', 'notes' => $stop->notes])->values());

    return {
        invoice: { open: false, loading: false, data: null, items: [], stopId: null, fileName: '', createOpen: false, createIndex: null, createForm: {}, createError: '', creating: false },
        stopMenu: { open: false, x: 0, y: 0, id: null },
        templateOpen: false,
        customerOpen: false,
        addStopOpen: false,
        editStopOpen: false,
        newStop: { title: '', address: '', customer_id: '', type: 'service', service_minutes: 30, priority: 3, window_start: '', window_end: '', contact_name: '', contact_phone: '', access_notes: '', parking_notes: '', notes: '' },
        editStop: { title: '', address: '', customer_id: '', type: 'service', service_minutes: 30, priority: 3, window_start: '', window_end: '', contact_name: '', contact_phone: '', access_notes: '', parking_notes: '', notes: '' },
        orderChanged: false,
        savingOrder: false,
        dragged: null,
        init() { this.initMap(); this.initDrag(); },
        openStopMenu(event, id) {
            this.stopMenu = { open: true, x: Math.min(event.clientX, window.innerWidth - 240), y: Math.min(event.clientY, window.innerHeight - 280), id };
        },
        closeStopMenu() { this.stopMenu.open = false; },
        preloadNewStopCustomer() { const customer = newStopCustomers.find(customer => String(customer.id) === String(this.newStop.customer_id)); if (!customer) return; this.newStop.address = customer.address || ''; this.newStop.contact_name = customer.name || ''; this.newStop.contact_phone = customer.phone || ''; },
        preloadEditStopCustomer() { const customer = newStopCustomers.find(customer => String(customer.id) === String(this.editStop.customer_id)); if (!customer) return; this.editStop.address = customer.address || ''; this.editStop.contact_name = customer.name || ''; this.editStop.contact_phone = customer.phone || ''; },
        openEditStop() { const stop = editableStops.find(stop => String(stop.id) === String(this.stopMenu.id)); if (!stop) return; const details = this.splitStopNotes(stop.notes || ''); this.editStop = { ...stop, ...details }; this.editStopOpen = true; },
        splitStopNotes(notes) { const result = { contact_name: '', contact_phone: '', access_notes: '', parking_notes: '', notes: '' }; const noteLines = []; String(notes).split('\n').forEach(line => { if (line.startsWith('Kontakt: ')) { const [name, phone] = line.slice(9).split(' · '); result.contact_name = name || ''; result.contact_phone = phone || ''; } else if (line.startsWith('Zugang: ')) result.access_notes = line.slice(8); else if (line.startsWith('Parken: ')) result.parking_notes = line.slice(8); else noteLines.push(line); }); result.notes = noteLines.join('\n').replace(/\n{3,}/g, '\n\n').trim(); return result; },
        stopUrl(suffix) { return `${stopBaseUrl}/${this.stopMenu.id}${suffix}`; },
        focusStopAction(type) {
            const card = document.querySelector(`[data-stop-id="${this.stopMenu.id}"]`);
            if (!card) return;
            const trigger = type === 'item' ? card.querySelector('button.text-cyan-400') : type === 'photo' ? card.querySelector('button.text-purple-400') : card.querySelector('input[placeholder*="Kommentar"]');
            if (trigger?.click) trigger.click(); else trigger?.focus();
            card.scrollIntoView({ behavior: 'smooth', block: 'center' });
        },
        removeCurrentStop() { if (confirm('Stopp wirklich von der Tour entfernen?')) this.$refs.removeStop.submit(); },
        initMap() {
            if (!window.tt || !tomTomKey) return;
            const dark = document.documentElement.getAttribute('data-theme') !== 'light';
            const map = tt.map({ key: tomTomKey, container: 'tour-map', center: [@js($tour->start_snapshot['lng'] ?? 6.06), @js($tour->start_snapshot['lat'] ?? 51.0)], zoom: 9, style: dark ? 'https://api.tomtom.com/style/1/style/22.2.1-9?map=basic_night' : undefined });
            map.on('load', () => {
                const addEndpointMarker = (location, label, classes) => {
                    if (!location || !Number.isFinite(Number(location.lng)) || !Number.isFinite(Number(location.lat))) return;
                    const marker = document.createElement('div');
                    marker.className = `flex h-7 w-7 items-center justify-center rounded-full border-2 border-white text-xs font-black text-white shadow-lg ${classes}`;
                    marker.textContent = label;
                    new tt.Marker({ element: marker }).setLngLat([location.lng, location.lat]).setPopup(new tt.Popup().setText(`${location.name || label}: ${location.address || ''}`)).addTo(map);
                };
                addEndpointMarker(startLocation, 'S', 'bg-emerald-600');
                addEndpointMarker(endLocation, 'Z', 'bg-rose-500');
                if (routePoints.length) {
                    map.addSource('route', { type: 'geojson', data: { type: 'Feature', geometry: { type: 'LineString', coordinates: routePoints.map(point => [point.lng, point.lat]) } } });
                    map.addLayer({ id: 'route', type: 'line', source: 'route', paint: { 'line-color': '#10b981', 'line-width': 5 } });
                    const bounds = new tt.LngLatBounds(); routePoints.forEach(point => bounds.extend([point.lng, point.lat])); map.fitBounds(bounds, { padding: 45 });
                }
                @foreach($tour->stops as $stop)
                const marker{{ $stop->id }} = document.createElement('div');
                marker{{ $stop->id }}.className = 'flex h-8 w-8 items-center justify-center rounded-full border-2 border-white bg-emerald-500 text-sm font-black text-white shadow-lg';
                marker{{ $stop->id }}.textContent = @js((string) $loop->iteration);
                new tt.Marker({ element: marker{{ $stop->id }} }).setLngLat([{{ $stop->longitude }}, {{ $stop->latitude }}]).setPopup(new tt.Popup().setText(@js($stop->title))).addTo(map);
                @endforeach
            });
        },
        initDrag() {
            const list = document.getElementById('tour-stop-list'); if (!list) return;
            list.querySelectorAll('[draggable]').forEach(element => {
                element.addEventListener('dragstart', () => this.dragged = element);
                element.addEventListener('dragover', event => { event.preventDefault(); const target = event.currentTarget; if (target !== this.dragged) list.insertBefore(this.dragged, target.getBoundingClientRect().top + target.offsetHeight / 2 < event.clientY ? target.nextSibling : target); });
            });
        },
        async saveOrder() { if (this.savingOrder) return; this.savingOrder = true; const ids = [...document.querySelectorAll('#tour-stop-list [data-stop-id]')].map(element => Number(element.dataset.stopId)); try { const response = await axios.post(reorderUrl, { stop_ids: ids }); if (response.data.success) location.reload(); } catch (error) { alert(error.response?.data?.message || 'Route konnte nicht neu berechnet werden.'); } finally { this.savingOrder = false; } },
        async parseInvoice(event, stopId) { const file = event.target.files[0]; if (!file) return; this.invoice = { open: true, loading: true, data: null, items: [], stopId, fileName: file.name, createOpen: false, createIndex: null, createForm: {}, createError: '', creating: false }; const formData = new FormData(); formData.append('invoice_file', file); try { const response = await axios.post(`${stopBaseUrl}/${stopId}/rechnung/parse`, formData); this.invoice.data = response.data; this.invoice.items = (response.data.items || []).map(item => ({ ...item, item_id: item.matched_item?.id || '', quantity: item.invoice_menge || 1, actual_net_price: item.invoice_netto_preis || 0 })); } catch (error) { alert(error.response?.data?.message || 'Analyse fehlgeschlagen'); this.invoice.open = false; } finally { this.invoice.loading = false; } },
        async createInvoiceItem() { this.invoice.creating = true; this.invoice.createError = ''; try { const response = await axios.post(`${stopBaseUrl}/${this.invoice.stopId}/rechnung/artikel`, this.invoice.createForm); const created = response.data.item; const row = this.invoice.items[this.invoice.createIndex]; row.item_id = created.id; row.status = 'exact_match'; row.matched_item = created; this.invoice.createOpen = false; } catch (error) { const messages = error.response?.data?.errors; this.invoice.createError = messages ? Object.values(messages).flat().join(' ') : (error.response?.data?.message || 'Artikel konnte nicht angelegt werden.'); } finally { this.invoice.creating = false; } },
        async commitInvoice() { const items = this.invoice.items.filter(item => item.item_id).map(item => ({ item_id: Number(item.item_id), quantity: Number(item.quantity), actual_net_price: Number(item.actual_net_price) })); if (!items.length) return alert('Keine Artikel ausgewählt.'); await axios.post(`${stopBaseUrl}/${this.invoice.stopId}/rechnung/commit`, { file_hash: this.invoice.data.file_hash, file_name: this.invoice.data.file_name, invoice_number: this.invoice.data.invoice_info?.number, invoice_date: null, items }); location.reload(); },
    };
}
document.addEventListener('DOMContentLoaded',()=>{const customers=@js($customers),defaults=@js($tour->stops->pluck('customer_id','id'));document.querySelectorAll('form[action$="/fotos"]').forEach(form=>{if(form.querySelector('[name="customer_id"]'))return;const stopId=form.action.match(/stopps\/(\d+)\/fotos/)?.[1],defaultId=defaults[stopId]||'';const select=document.createElement('select');select.name='customer_id';select.className='sck-input rounded-xl text-sm';select.innerHTML=`<option value="${defaultId}">Stopp-Kunde übernehmen</option><option value="">Keine Kundenzuordnung</option>`+customers.map(c=>`<option value="${c.id}">${c.name}</option>`).join('');const fields=form.querySelector('.photo-upload-fields');fields?.insertBefore(select,fields.querySelector('button'))})});
</script>
<script>
document.addEventListener('DOMContentLoaded', () => {
    const list = document.getElementById('tour-stop-list');
    if (!list) return;
    let dragged = null;
    let originalOrder = [];
    list.addEventListener('dragstart', event => { dragged = event.target.closest('[data-stop-id]'); originalOrder = [...list.querySelectorAll('[data-stop-id]')].map(el => el.dataset.stopId); event.dataTransfer.effectAllowed = 'move'; });
    list.addEventListener('dragover', event => {
        event.preventDefault(); const target = event.target.closest('[data-stop-id]');
        if (!dragged || !target || target === dragged) return;
        list.insertBefore(dragged, event.clientY > target.getBoundingClientRect().top + target.offsetHeight / 2 ? target.nextSibling : target);
    });
    list.addEventListener('dragend', () => {
        if (!dragged) return; dragged = null;
        const currentOrder = [...list.querySelectorAll('[data-stop-id]')].map(el => el.dataset.stopId);
        if (currentOrder.some((id, index) => id !== originalOrder[index])) window.dispatchEvent(new CustomEvent('tour-order-changed'));
    });
});
</script>
@endpush
